### Generate function to compute difference in dates 
compute_date_diff <- function(df, date_col1, date_col2, new_col_name) {
  # Ensure date columns are in POSIXct format
  date1 <- as.POSIXct(df[[date_col1]], tz = "UTC")
  date2 <- as.POSIXct(df[[date_col2]], tz = "UTC")
  # Compute difference in days
  diff_days <- as.numeric(difftime(date1, date2, units = "days"))
  # Add to dataframe
  df[[new_col_name]] <- diff_days
  return(df)
}



### Function to compute days to cutoff date (July 31, 2024)
fill_missing_diff_days <- function(df, date_col, diff_col, cutoff = "2024-07-31", new_col = "diff_years") {
  # Ensure cutoff is Date
  cutoff_date <- as.Date(cutoff)
  # Loop through rows where diff_col is NA
  for (i in seq_len(nrow(df))) {
    if (is.na(df[[diff_col]][i])) {
      date_val <- df[[date_col]][i]
      if (!is.na(date_val)) {
        diff_days <- as.numeric(difftime(as.POSIXct(cutoff_date), as.POSIXct(date_val, tz = "UTC"), units = "days"))
        df[[diff_col]][i] <- diff_days
      }
    }
  }
  # Convert to years
  df[[new_col]] <- df[[diff_col]] / 365
  return(df)
}


