### 6.2 Run Cox regression models----

### Generate function that computes Cox regression models, get summary, 
### compute c-index, check PH assumption, fit survival curves and plot them
### Only works for models that do not include a time interaction


run_cox_model <- function(formula, data, model_name) {
  ### Fit Cox model
  formula <- as.formula(formula)
  model <- coxph(formula, data = data); model_summary <- summary(model)
  ### Check proportional hazard assumption
  if (model_name != "null_model") {
    pha=cox.zph(model)}
  ### Compute C-index
  c_index <- model_summary$concordance
  ### Fit survival curves
  surv_fit <- survfit(model)
  ### Log-rank test & p-value
  lr_test <- model_summary$logtest[1]; p_val <- model_summary$logtest[3]
  ### Plot survival curve
  plot(surv_fit, xlab = "Time (years)", ylab = "Survival Probability", ylim = c(0, 1))
  ### Save model summary to a text file
  summary_filename <- paste0("Cox_model_", model_name, "_summary.txt")
  #capture.output(model_summary, file = summary_filename)
  ### Return results for null model (no PH assumption)
  if (model_name == "null_model") {
    return(list(model = model, summary = model_summary,  c_index = c_index,
                log_rank_test = lr_test, p_value = p_val))}
  
  if (model_name != "null_model") {
    return(list(model = model, summary = model_summary, ph_assumption=pha, c_index = c_index,
                log_rank_test = lr_test, p_value = p_val))}
}



