    geom_step(aes(y = lower), color = model_color, linewidth = 0.2, alpha = 1) +
    scale_x_continuous(
      limits = x_limits,
      breaks = seq(0, ceiling(max(x_limits)), by = 1)
    ) +
    scale_y_continuous(
      limits = y_limits,
      breaks = y_breaks
    )
  
  ### Save as SVG (Illustrator-ready, editable text)
  svg_filename <- file.path(path, paste0("cox_surv_curve_", model_name, "_panel.svg"))
  
  svglite::svglite(
    file = svg_filename,
    width = 4.6 / 2.54,   # cm ??? inches
    height = 4.6 / 2.54
  )
  
  print(g)
  dev.off()
  
  ### Display in R
  print(g)
}

