create_time_table <- function(
    model,
    data,
    time_var,
    event_var,
    time_points = seq(0, 7, by = 1),
    output_name = "time_table",
    path = "."
) {
  
  
  
  # Ensure proper format
  data <- as.data.frame(data)
  
  ### Risk groups
  risk_scores <- predict(model, type = "lp")
  
  risk_group <- cut(
    risk_scores,
    breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1), na.rm = TRUE),
    labels = c("Low", "Medium", "High"),
    include.lowest = TRUE
  )
  
  data$risk_group <- factor(risk_group, levels = c("Low", "Medium", "High"))
  
  ### Survival fit
  surv_formula <- as.formula(
    paste0("Surv(", time_var, ", ", event_var, ") ~ risk_group")
  )
  
  fit <- survfit(surv_formula, data = data)
  
  ### Fixed time table
  fit_summary_fixed <- summary(fit, times = time_points)
  
  time_table_fixed <- data.frame(
    strata   = fit_summary_fixed$strata,
    time     = fit_summary_fixed$time,
    n_risk   = fit_summary_fixed$n.risk,
    n_event  = fit_summary_fixed$n.event,
    n_censor = fit_summary_fixed$n.censor
  )
  
  ### Cumulative values
  time_table_cum <- time_table_fixed %>%
    group_by(strata) %>%
    arrange(time) %>%
    mutate(
      cum_events = cumsum(n_event),
      cum_censor = cumsum(n_censor)
    ) %>%
    ungroup() %>%
    arrange(strata, time)
  
  ### Save CSV
  write.csv(
    time_table_cum,
    file = file.path(path, paste0(output_name, ".csv")),
    row.names = FALSE
  )
  
  ### Return table
  return(time_table_cum)
}




