compare_risk_simple <- function(variable_name, variable_type, model_idx, 
                                model_options, data, y_label, custom_colors, path,integer_y=FALSE) {
  
  # Compute risk scores
  risk_scores <- predict(model_options[[model_idx]], type="lp")
  data$risk_scores <- risk_scores
  
  # Continuous variables
  if(variable_type == "continuous") {
    formula <- as.formula(paste("risk_scores ~", variable_name))
    lm_res <- summary(lm(formula, data=data))
    t_val <- lm_res$coefficients[variable_name, "t value"]
    p_val <- lm_res$coefficients[variable_name, "Pr(>|t|)"]
    
    # Scatterplot with regression line
    p_scatter <- ggplot(data, aes(x=.data[[variable_name]], y=risk_scores)) +
      geom_point(color=custom_colors[1], alpha=0.5, size=1.5, stroke=0.1) +
      geom_smooth(method="lm", se=TRUE, color=custom_colors[1], fill=custom_colors[1], alpha=0.15, linewidth=0.3) +
      labs(x=y_label, y="Relative risk score") +
      theme_classic(base_family="Arial") +
      theme(
        axis.title = element_text(size = 8),
        axis.text  = element_text(size = 8),
        axis.line  = element_line(linewidth = 0.4),
        axis.ticks = element_line(linewidth = 0.4),
        plot.margin = margin(2, 2, 2, 2, "mm")
      )
    
    if(integer_y) {
      p_scatter <- p_scatter +
        scale_y_continuous(
          breaks = seq(
            floor(min(data[[variable_name]], na.rm = TRUE)),
            ceiling(max(data[[variable_name]], na.rm = TRUE)),
            by = 2
          )
        )
    }
    
    
    svglite::svglite(file=file.path(path, paste0("scatter_risk_score_", variable_name, ".svg")),
                     width=4.6/2.54, height=4.6/2.54)
    print(p_scatter); dev.off()
    
    return(list(lm_summary=lm_res, t_val=t_val, p_val=p_val))
  }
  
  # Categorical variables (sex, apoe)
  if(variable_type == "categorical") {
    formula <- as.formula(paste("risk_scores ~", variable_name))
    t_res <- t.test(formula, data=data)
    
    # Box + violin plot
    p_box <- ggplot(data, aes(x=.data[[variable_name]], y=risk_scores, fill=.data[[variable_name]])) +
      geom_violin(trim=FALSE, linewidth=0.3) +
      geom_boxplot(width=0.3, outlier.shape=NA, linewidth=0.3) +
      geom_jitter(width=0.15, color="black", alpha=0.25, size=1.5, stroke = 0.1) +
      scale_fill_manual(values=custom_colors) +
      labs(x=y_label, y="Relative risk score") +
      theme_classic(base_family="Arial") +
      theme(
        axis.title = element_text(size = 8),
        axis.text  = element_text(size = 8),
        axis.line  = element_line(linewidth = 0.4),
        axis.ticks = element_line(linewidth = 0.4),
        plot.margin = margin(2, 2, 2, 2, "mm"),
        legend.position="none")
    
    svglite::svglite(file=file.path(path, paste0("box_risk_score_", variable_name, ".svg")),
                     width=4.6/2.54, height=4.6/2.54)
    print(p_box); dev.off()
    
    return(list(t_test=t_res))
  }
}







