### 8. MCI Cox regression survival analysis with time interactions----

### 8.1 Run Cox regressions including time interactions----

### Generate function to run a Cox model including an interaction term

run_cox_model_time_int <- function(formula, data, model_name) {
  formula <- as.formula(formula)
  model <- coxph(formula, data = data, tt = function(x, time, ...) x * time)
  model_summary <- summary(model)
  c_index <- model_summary$concordance
  lr_test <- model_summary$logtest[1]
  p_val <- model_summary$logtest[3]
  summary_filename <- paste0("Cox_model_", model_name, "_summary.txt")
  #capture.output(model_summary, file = summary_filename)
  return(list(model = model, summary = model_summary, c_index = c_index, log_rank_test = lr_test, p_value = p_val))
}



