### 8.3 Compute relative risk and plot linear predictor as a function of time----

### Function: Compute relative risks + Illustrator-friendly plotting
compute_relative_risks <- function(data, biomarker, time_var, event_var, covariates = NULL, 
                                   time_points = 1:7, id_var = "pscid", plot = TRUE, model_name = NULL, 
                                   path = ".", include_ci = TRUE, overlay_baseline = FALSE, 
                                   save_csv = FALSE, csv_filename = NULL, scale = "log") {
  
  # Check scale
  if (!scale %in% c("log", "exp")) stop("scale must be 'log' or 'exp'")
  
  # Build Cox formula
  all_covariates <- paste(c(covariates, biomarker, paste0("tt(", biomarker, ")")), collapse = " + ")
  cox_formula <- as.formula(paste0("Surv(", time_var, ", ", event_var, ") ~ ", all_covariates))
  
  # Fit Cox model with time interaction
  cox_model <- coxph(cox_formula, data = data, tt = function(x, time, ...) x * time)
  
  # Compute linear predictors
  linear_predictor <- predict(cox_model, type = "lp", newdata = data)
  
  coefs <- coef(cox_model)
  vcov_mat <- vcov(cox_model)
  
  biom_coef <- coefs[biomarker]
  interaction_name <- paste0("tt(", biomarker, ")")
  interaction_coef <- coefs[interaction_name]
  
  se_biom <- sqrt(vcov_mat[biomarker, biomarker])
  se_inter <- sqrt(vcov_mat[interaction_name, interaction_name])
  cov_biom_inter <- vcov_mat[biomarker, interaction_name]
  
  lp_no_main <- linear_predictor - data[[biomarker]] * biom_coef
  
  # Compute relative risks for each time point
  relative_risks <- lapply(time_points, function(t) {
    biom <- data[[biomarker]]
    lp <- lp_no_main + biom * (biom_coef + interaction_coef * t)
    
    if (include_ci) {
      se_lp <- sqrt((biom^2) * (se_biom^2 + t^2 * se_inter^2 + 2 * t * cov_biom_inter))
      lower <- lp - 1.96 * se_lp
      upper <- lp + 1.96 * se_lp
      
      if (scale == "exp") {
        return(data.frame(lp = exp(lp), lower = exp(lower), upper = exp(upper)))
      } else {
        return(data.frame(lp = lp, lower = lower, upper = upper))
      }
    } else {
      return(data.frame(lp = if (scale == "exp") exp(lp) else lp))
    }
  })
  
  # Combine results
  rr_df <- do.call(rbind, lapply(seq_along(time_points), function(i) {
    df <- relative_risks[[i]]
    df[[id_var]] <- data[[id_var]]
    df$biomarker_value <- data[[biomarker]]
    df$time <- time_points[i]
    return(df)
  }))
  
  rr_df <- rr_df[, c(id_var, "time", "biomarker_value", "lp", if (include_ci) c("lower", "upper") else NULL)]
  names(rr_df)[names(rr_df) == "lp"] <- "relative_risk"
  
  # Save CSV if requested
  if (save_csv && !is.null(csv_filename)) {
    write.csv(rr_df, file = file.path(path, csv_filename), row.names = FALSE)
  }
  
  # Plotting (Illustrator-friendly)
  if (plot && !is.null(model_name)) {
    
    # Colors
    parula_colors <- c("#352A87", "#3B52A1", "#3F7FBA", "#469BBA", "#58B89E", "#84CA79", "#D9D93A")
    if (length(time_points) != length(parula_colors)) stop("Number of time points must match parula_colors length")
    names(parula_colors) <- as.character(time_points)
    
    # Labels
    xlab <- switch(biomarker,
                   "age_z" = "Age (z-score)",
                   "education_z" = "Education (z-score)",
                   "tau_meta_roi_meg_delta_z" = "Delta power (z-score)",
                   "tau_meta_roi_meg_theta_z" = "Theta power (z-score)",
                   "tau_meta_roi_meg_alpha_z" = "Alpha power (z-score)",
                   "tau_meta_roi_meg_beta_z" = "Beta power (z-score)",
                   "tau_meta_roi_meg_gamma1_z" = "Gamma power (z-score)",
                   "tau_meta_roi_meg_gamma2_z" = "Gamma2 power (z-score)",
                   "hippocampal_volume_z" = "Hipp. volume (z-score)",
                   "Ab42_40_ratio_z" = "A??42/40 ratio (z-score)",
                   "ptau_217_z" = "p-tau217 (z-score)",
                   "amyloid_index_z" = "Neocortical A?? (z-score)",
                   "tau_entorhinal_z" = "Entorhinal tau (z-score)",
                   biomarker)
    
    ylab <- if (scale == "exp") "Relative Risk (HR)" else "Relative risk score"
    
    # Base plot
    p <- ggplot(rr_df, aes(x = biomarker_value, y = relative_risk, color = factor(time))) +
      geom_point(size = 0.6, alpha = 0.7) +
      geom_smooth(method = "lm", aes(group = time), se = FALSE, linewidth = 0.6) +
      scale_color_manual(values = parula_colors, name = "Time") +
      guides(color = guide_legend(nrow = 1))
    
    # CI ribbons
    if (include_ci) {
      p <- p + geom_ribbon(aes(ymin = lower, ymax = upper, fill = factor(time)), alpha = 0.15, color = NA) +
        scale_fill_manual(values = parula_colors, guide = "none")
    }
    
    # Adaptive integer y-axis
    p <- p + scale_y_continuous(
      breaks = function(x) {
        bks <- pretty(x)
        bks_int <- unique(round(bks))
        bks_int[bks_int >= min(x) & bks_int <= max(x)]
      },
      labels = scales::label_number(accuracy = 1)
    )
    
    # Color scale
    p <- p + scale_color_manual(values = parula_colors, name = "Time")
    
    # Theme
    p <- p +
      labs(x = xlab, y = ylab) +
      theme_classic(base_family = "Arial") +
      theme(
        axis.title = element_text(size = 8),
        axis.text  = element_text(size = 8),
        axis.line  = element_line(linewidth = 0.4),
        axis.ticks = element_line(linewidth = 0.4),
        legend.position = "none",
        legend.title = element_text(size = 8),
        legend.text  = element_text(size = 7),
        legend.key.width = unit(0.4, "cm"),
        legend.spacing.x = unit(0.05, "cm"),
        legend.margin = margin(0, 0, 0, 0),
        legend.box.margin = margin(0, 0, 0, 0),
        plot.margin = margin(2, 2, 2, 2, "mm")
      )
    
    # Save as SVG for Illustrator
    svg_filename <- file.path(path, paste0(model_name, "_panel.svg"))
    svglite::svglite(file = svg_filename, width = 4.6/2.54, height = 4.6/2.54) # cm ??? inches
    print(p)
    dev.off()
    
    # Also show plot in R
    print(p)
  }
  
  return(rr_df)
}



