library(corrplot)
library(svglite)

plot_aic_matrix <- function(
    model_list,
    model_names,
    output_name = "AIC_matrix",
    path = "."
) {
  
  
  # Compute AIC values
  values_AIC <- sapply(model_list, AIC)
  
  # Difference matrix
  diff_matrix <- outer(values_AIC, values_AIC, "-")
  diff_matrix <- diff_matrix * (-1)
  
  colnames(diff_matrix) <- model_names
  rownames(diff_matrix) <- model_names
  
  diff_vals <- diff_matrix
  diag(diff_matrix) <- 0
  
  # Create star matrix (LOWER TRIANGLE ONLY)
  star_matrix <- matrix("", nrow = nrow(diff_vals), ncol = ncol(diff_vals))
  
  for(i in 1:nrow(diff_vals)) {
    for(j in 1:ncol(diff_vals)) {
      
      if(i > j) {   # ???? only lower triangle
        val <- diff_vals[i, j]
        
        if(!is.na(val)) {
          if(abs(val) > 10) {
            star_matrix[i, j] <- "**"
          } else if(abs(val) > 2) {
            star_matrix[i, j] <- "*"
          }
        }
      }
    }
  }
  
  
  # Color scale
  color_scale <- colorRampPalette(c("#71bfff", "white", "#fc9c9c"))(100)
  
  # Save SVG (slightly larger ??? better scaling)
  svglite::svglite(
    file = file.path(path, paste0(output_name, ".svg")),
    width = 7 / 2.54,
    height = 7 / 2.54
  )
  
  # ???? remove ALL margins (outer + inner)
  par(mar = c(0, 0, 0, 0), mai = c(0, 0, 0, 0))
  
  # Plot matrix
  corrplot(
    corr = diff_matrix,
    method = "color",
    col = color_scale,
    is.corr = FALSE,
    type = "lower",
    diag = FALSE,
    outline = FALSE,
    addCoef.col = NULL,
    tl.cex = 0.6,          # ~8 pt labels
    tl.col = "black",
    tl.srt = 45,
    tl.offset = 0.1,       # ???? tighter ??? reduces top whitespace
    cl.pos = "n",          # no legend
    bg = "white",
    addgrid.col = "black"
  )
  
  # Add stars (lower triangle only)
  n <- nrow(diff_matrix)
  
  for(i in 1:n) {
    for(j in 1:n) {
      
      if(i > j) {   # ???? enforce lower triangle
        label <- star_matrix[i, j]
        
        if(label != "") {
          text(
            x = j,
            y = n - i + 1,
            labels = label,
            cex = 0.6   # ~8 pt
          )
        }
      }
    }
  }
  
  dev.off()
  
  return(diff_vals)
}




