### 12. Plot correlations coefficients between model features----

### Function to compute p-values for correlations
cor_pvalues <- function(mat) {
  p_mat <- matrix(NA, ncol = ncol(mat), nrow = nrow(mat))
  colnames(p_mat) <- colnames(mat)
  rownames(p_mat) <- rownames(mat)
  
  for (i in 1:(ncol(mat) - 1)) {
    for (j in (i + 1):ncol(mat)) {
      test <- cor.test(mat[, i], mat[, j], use = "complete.obs")
      p_mat[i, j] <- test$p.value
      p_mat[j, i] <- test$p.value  # Symmetric matrix
    }
  }
  diag(p_mat) <- NA  # No p-values on the diagonal
  return(p_mat)
}

