plot_correlation_matrix <- function(
    data,
    variables,
    labels = NULL,
    output_name = "correlation_matrix",
    path = "."
) {
  
  library(corrplot)
  library(svglite)
  
  # Subset data
  mat <- data[, variables]
  
  # Compute correlation matrix
  cor_matrix <- cor(mat, use = "complete.obs")
  
  # Labels
  if(!is.null(labels)) {
    rownames(cor_matrix) <- labels
    colnames(cor_matrix) <- labels
  }
  
  # Create star matrix (LOWER TRIANGLE ONLY)
  star_matrix <- matrix("", nrow = nrow(cor_matrix), ncol = ncol(cor_matrix))
  
  for(i in 1:nrow(cor_matrix)) {
    for(j in 1:ncol(cor_matrix)) {
      
      if(i > j) {
        val <- cor_matrix[i, j]
        
        if(!is.na(val)) {
          if(abs(val) > 0.5) {
            star_matrix[i, j] <- "**"
          } else if(abs(val) > 0.3) {
            star_matrix[i, j] <- "*"
          }
        }
      }
    }
  }
  
  # Color scale
  color_scale <- colorRampPalette(c("#71bfff","white","#fc9c9c"))(100)
  
  # Save SVG
  svglite::svglite(
    file = file.path(path, paste0(output_name, ".svg")),
    width = 7 / 2.54,
    height = 7 / 2.54
  )
  
  par(mar = c(0, 0, 0, 0), mai = c(0, 0, 0, 0))
  
  # Plot matrix (no numbers)
  corrplot(
    cor_matrix,
    method = "color",
    col = color_scale,
    is.corr = TRUE,
    type = "lower",
    diag = FALSE,
    outline = FALSE,
    addCoef.col = NULL,
    tl.cex = 0.6,        # ~8 pt labels
    tl.col = "black",
    tl.srt = 45,
    tl.offset = 0.1,
    cl.pos = "b",        # ???? color legend at bottom
    cl.cex = 0.6,        # ~8 pt legend text
    cl.length = 5,       # cleaner ticks
    cl.align.text = "c",
    bg = "white",
    addgrid.col = "black"
  )
  
  # Add stars (lower triangle only)
  n <- nrow(cor_matrix)
  
  for(i in 1:n) {
    for(j in 1:n) {
      
      if(i > j) {
        label <- star_matrix[i, j]
        
        if(label != "") {
          text(
            x = j,
            y = n - i + 1,
            labels = label,
            cex = 0.6   # ~8 pt
          )
        }
      }
    }
  }
  
  dev.off()
  
  return(cor_matrix)
}





